namespace hirct {

namespace {

static constexpr const char *AUTO_GENERATED_HEADER =
    "// AUTO-GENERATED by hirct-gen \xe2\x80\x94 DO NOT EDIT\n";

} // namespace

static uint64_t resolve_reset_encoding(const RegisterView &reg) {
  if (reg.reset_value) {
    if (auto c = reg.reset_value.getDefiningOp<circt::hw::ConstantOp>())
      return c.getValue().zextOrTrunc(64).getZExtValue();
  }
  return 0;
}

GenFuncModel::GenFuncModel(circt::hw::HWModuleOp hw_module,
                           mlir::ModuleOp mlir_module)
    : hw_module_(hw_module), mlir_module_(mlir_module) {}

bool GenFuncModel::emit(const std::string &output_dir) {
  last_error_reason_.clear();

  auto fsm_views = identify_fsm_registers(hw_module_);
  if (fsm_views.empty()) {
    last_error_reason_ = "no FSM found";
    return false;
  }

  if (fsm_views.size() > 1)
    std::cerr << "GenFuncModel: multiple FSMs found, using first\n";

  const auto &fsm = fsm_views[0];
  std::string name = hw_module_.getSymName().str();

  std::string func_model_dir = output_dir + "/func_model";
  if (mkdir(func_model_dir.c_str(), 0755) != 0 && errno != EEXIST) {
    last_error_reason_ = "cannot create func_model directory";
    return false;
  }

  if (!emit_header(func_model_dir, name, fsm))
    return false;
  if (!emit_impl(func_model_dir, name, fsm))
    return false;

  return true;
}

bool GenFuncModel::emit_header(const std::string &dir, const std::string &name,
                               const FSMView &fsm) {
  std::string path = dir + "/" + name + ".h";
  std::ofstream ofs(path);
  if (!ofs) {
    last_error_reason_ = "cannot open " + path;
    return false;
  }

  std::string guard = name + "_FUNC_H";
  for (auto &c : guard)
    c = static_cast<char>(std::toupper(static_cast<unsigned char>(c)));

  ofs << AUTO_GENERATED_HEADER;
  ofs << "#ifndef " << guard << "\n";
  ofs << "#define " << guard << "\n\n";
  ofs << "#include <cstdint>\n\n";

  ofs << "class " << name << "_func {\npublic:\n";

  ofs << "  enum class State : uint8_t {";
  bool first = true;
  for (const auto &st : fsm.states) {
    if (!first)
      ofs << ",";
    ofs << " S" << st.encoding << " = " << st.encoding;
    first = false;
  }
  ofs << " };\n\n";

  // IR 분석으로 확인된 clock port 셋 구성 (이름 휴리스틱 대신 SSOT 사용)
  auto cdm = hirct::build_clock_domain_map(hw_module_, mlir_module_);
  llvm::StringSet<> clock_port_names;
  for (const auto &domain : cdm.domains)
    clock_port_names.insert(domain.clock_port_name);

  auto ports = hirct::get_ports(hw_module_);
  ofs << "  struct Ports {\n";
  for (const auto &p : ports) {
    if (clock_port_names.count(p.name) || hirct::is_reset_port(p.name))
      continue;
    unsigned w = p.width;
    if (w == 0)
      w = 1;
    ofs << "    " << hirct::cpp_type_for_width(w) << " " << p.name << ";\n";
  }
  ofs << "  };\n\n";

  ofs << "  void reset();\n";
  ofs << "  void tick(Ports &io);\n";
  ofs << "  State state() const { return state_; }\n\n";

  ofs << "private:\n";
  uint64_t reset_enc = resolve_reset_encoding(fsm.state_reg);
  ofs << "  State state_ = State::S" << reset_enc << ";\n";
  for (const auto &dreg : fsm.data_regs) {
    unsigned w = dreg.width;
    if (w == 0)
      w = 1;
    ofs << "  " << hirct::cpp_type_for_width(w) << " " << dreg.name
        << "_ = 0;\n";
  }

  ofs << "};\n\n";
  ofs << "#endif // " << guard << "\n";
  return true;
}

bool GenFuncModel::emit_impl(const std::string &dir, const std::string &name,
                             const FSMView &fsm) {
  std::string path = dir + "/" + name + ".cpp";
  std::ofstream ofs(path);
  if (!ofs) {
    last_error_reason_ = "cannot open " + path;
    return false;
  }

  std::string cls = name + "_func";
  ofs << AUTO_GENERATED_HEADER;
  ofs << "#include \"" << name << ".h\"\n\n";

  uint64_t reset_enc = resolve_reset_encoding(fsm.state_reg);
  ofs << "void " << cls << "::reset() {\n";
  ofs << "  state_ = State::S" << reset_enc << ";\n";
  for (const auto &dreg : fsm.data_regs)
    ofs << "  " << dreg.name << "_ = 0;\n";
  ofs << "}\n\n";

  ofs << "void " << cls << "::tick(Ports &io) {\n";
  ofs << "  switch (state_) {\n";

  for (const auto &st : fsm.states) {
    ofs << "  case State::S" << st.encoding << ":\n";

    std::vector<const FSMTransitionView *> from_trans;
    for (const auto &t : fsm.transitions) {
      if (t.from_encoding == st.encoding)
        from_trans.push_back(&t);
    }

    if (from_trans.size() == 1) {
      const auto &t = *from_trans[0];
      if (t.condition) {
        std::string cond = resolve_condition_expr(t.condition);
        ofs << "    if (" << cond << ") state_ = State::S" << t.to_encoding
            << ";\n";
      } else {
        ofs << "    state_ = State::S" << t.to_encoding << ";\n";
      }
    } else if (from_trans.size() >= 2) {
      llvm::SmallVector<const FSMTransitionView *> cond_trans_list;
      const FSMTransitionView *default_trans = nullptr;
      for (auto *t : from_trans) {
        if (t->condition)
          cond_trans_list.push_back(t);
        else
          default_trans = t;
      }
      if (!cond_trans_list.empty()) {
        for (size_t i = 0; i < cond_trans_list.size(); ++i) {
          const auto *ct = cond_trans_list[i];
          std::string cond = resolve_condition_expr(ct->condition);
          if (i == 0)
            ofs << "    if (" << cond << ")\n";
          else
            ofs << "    else if (" << cond << ")\n";
          ofs << "      state_ = State::S" << ct->to_encoding << ";\n";
        }
        if (default_trans) {
          ofs << "    else\n";
          ofs << "      state_ = State::S" << default_trans->to_encoding
              << ";\n";
        }
      } else if (default_trans) {
        ofs << "    state_ = State::S" << default_trans->to_encoding << ";\n";
      }
    }

    for (const auto &upd : fsm.data_reg_updates) {
      if (upd.state_encoding != st.encoding)
        continue;
      std::string val_expr = resolve_value_expr(upd.new_value, fsm);
      if (upd.condition) {
        ofs << "    if (" << resolve_condition_expr(upd.condition) << ")\n";
        ofs << "      " << upd.reg_name << "_ = " << val_expr << ";\n";
      } else {
        ofs << "    " << upd.reg_name << "_ = " << val_expr << ";\n";
      }
    }

    for (const auto &assign : fsm.output_assignments) {
      if (assign.state_encoding != st.encoding)
        continue;
      ofs << "    io." << assign.port_name << " = "
          << resolve_value_expr(assign.value, fsm) << ";\n";
    }

    ofs << "    break;\n";
  }

  ofs << "  }\n";
  ofs << "}\n";

  return true;
}

std::string GenFuncModel::resolve_value_expr(mlir::Value v,
                                              const FSMView &fsm) {
  if (auto arg = mlir::dyn_cast<mlir::BlockArgument>(v)) {
    auto port_list = hw_module_.getPortList();
    unsigned input_idx = 0;
    for (auto &p : port_list) {
      if (p.isInput()) {
        if (input_idx == arg.getArgNumber())
          return "io." + p.getName().str();
        ++input_idx;
      }
    }
    return "/* unresolved: block_arg */";
  }

  mlir::Operation *op = v.getDefiningOp();
  if (!op)
    return "/* unresolved */";

  if (auto c = mlir::dyn_cast<circt::hw::ConstantOp>(op)) {
    uint64_t val = c.getValue().zextOrTrunc(64).getZExtValue();
    return std::to_string(val);
  }

  if (auto compreg = mlir::dyn_cast<circt::seq::CompRegOp>(op)) {
    if (fsm.state_reg.op == compreg.getOperation())
      return "state_";
    for (const auto &dreg : fsm.data_regs) {
      if (dreg.op == compreg.getOperation())
        return dreg.name + "_";
    }
    return "/* unresolved: compreg */";
  }

  if (mlir::isa<circt::comb::AddOp>(op)) {
    std::ostringstream oss;
    oss << "(";
    for (unsigned i = 0; i < op->getNumOperands(); ++i) {
      if (i > 0)
        oss << ") + (";
      oss << resolve_value_expr(op->getOperand(i), fsm);
    }
    oss << ")";
    return oss.str();
  }

  if (auto icmp = mlir::dyn_cast<circt::comb::ICmpOp>(op)) {
    std::string lhs = resolve_value_expr(icmp.getLhs(), fsm);
    std::string rhs = resolve_value_expr(icmp.getRhs(), fsm);
    using P = circt::comb::ICmpPredicate;
    auto pred = icmp.getPredicate();
    if (pred == P::eq || pred == P::ceq || pred == P::weq)
      return "((" + lhs + ") == (" + rhs + "))";
    if (pred == P::ne || pred == P::cne || pred == P::wne)
      return "((" + lhs + ") != (" + rhs + "))";
    const char *op_str = "??";
    switch (pred) {
    case P::ult: op_str = "<"; break;
    case P::ule: op_str = "<="; break;
    case P::ugt: op_str = ">"; break;
    case P::uge: op_str = ">="; break;
    case P::slt: op_str = "<"; break;
    case P::sle: op_str = "<="; break;
    case P::sgt: op_str = ">"; break;
    case P::sge: op_str = ">="; break;
    default: break;
    }
    return "((" + lhs + ") " + op_str + " (" + rhs + "))";
  }

  if (mlir::isa<circt::comb::AndOp>(op)) {
    std::ostringstream oss;
    oss << "(";
    for (unsigned i = 0; i < op->getNumOperands(); ++i) {
      if (i > 0)
        oss << ") & (";
      oss << resolve_value_expr(op->getOperand(i), fsm);
    }
    oss << ")";
    return oss.str();
  }

  if (mlir::isa<circt::comb::OrOp>(op)) {
    std::ostringstream oss;
    oss << "(";
    for (unsigned i = 0; i < op->getNumOperands(); ++i) {
      if (i > 0)
        oss << ") | (";
      oss << resolve_value_expr(op->getOperand(i), fsm);
    }
    oss << ")";
    return oss.str();
  }

  if (mlir::isa<circt::comb::XorOp>(op)) {
    std::ostringstream oss;
    oss << "(";
    for (unsigned i = 0; i < op->getNumOperands(); ++i) {
      if (i > 0)
        oss << ") ^ (";
      oss << resolve_value_expr(op->getOperand(i), fsm);
    }
    oss << ")";
    return oss.str();
  }

  std::string op_name = op->getName().getStringRef().str();
  return "/* unresolved: " + op_name + " */";
}

std::string GenFuncModel::resolve_condition_expr(mlir::Value cond) {
  if (!cond)
    return "";

  // BlockArgument → 포트 이름으로 해석
  if (auto arg = mlir::dyn_cast<mlir::BlockArgument>(cond)) {
    auto port_list = hw_module_.getPortList();
    unsigned input_idx = 0;
    for (auto &p : port_list) {
      if (p.isInput()) {
        if (input_idx == arg.getArgNumber())
          return "io." + p.getName().str();
        ++input_idx;
      }
    }
    return "/* unresolved: block_arg */";
  }

  mlir::Operation *op = cond.getDefiningOp();
  if (!op)
    return "/* unresolved condition */";

  // hw.constant → 정수 리터럴
  if (auto c = mlir::dyn_cast<circt::hw::ConstantOp>(op)) {
    uint64_t v = c.getValue().zextOrTrunc(64).getZExtValue();
    return std::to_string(v);
  }

  // comb.icmp — eq/ne 및 기타 비교 연산
  if (auto icmp = mlir::dyn_cast<circt::comb::ICmpOp>(op)) {
    std::string lhs = resolve_condition_expr(icmp.getLhs());
    std::string rhs = resolve_condition_expr(icmp.getRhs());
    using P = circt::comb::ICmpPredicate;
    auto pred = icmp.getPredicate();
    if (pred == P::eq || pred == P::ceq || pred == P::weq)
      return "((" + lhs + ") == (" + rhs + "))";
    if (pred == P::ne || pred == P::cne || pred == P::wne)
      return "((" + lhs + ") != (" + rhs + "))";
    const char *op_str = "??";
    switch (pred) {
    case P::ult: op_str = "<"; break;
    case P::ule: op_str = "<="; break;
    case P::ugt: op_str = ">"; break;
    case P::uge: op_str = ">="; break;
    case P::slt: op_str = "<"; break;
    case P::sle: op_str = "<="; break;
    case P::sgt: op_str = ">"; break;
    case P::sge: op_str = ">="; break;
    default: break;
    }
    return "((" + lhs + ") " + op_str + " (" + rhs + "))";
  }

  // comb.and — variadic
  if (mlir::isa<circt::comb::AndOp>(op)) {
    std::ostringstream oss;
    oss << "(";
    for (unsigned i = 0; i < op->getNumOperands(); ++i) {
      if (i > 0)
        oss << ") & (";
      oss << resolve_condition_expr(op->getOperand(i));
    }
    oss << ")";
    return oss.str();
  }

  // comb.or — variadic
  if (mlir::isa<circt::comb::OrOp>(op)) {
    std::ostringstream oss;
    oss << "(";
    for (unsigned i = 0; i < op->getNumOperands(); ++i) {
      if (i > 0)
        oss << ") | (";
      oss << resolve_condition_expr(op->getOperand(i));
    }
    oss << ")";
    return oss.str();
  }

  // comb.xor — variadic
  if (mlir::isa<circt::comb::XorOp>(op)) {
    std::ostringstream oss;
    oss << "(";
    for (unsigned i = 0; i < op->getNumOperands(); ++i) {
      if (i > 0)
        oss << ") ^ (";
      oss << resolve_condition_expr(op->getOperand(i));
    }
    oss << ")";
    return oss.str();
  }

  // 미지원 패턴 fallback
  std::string op_name = op->getName().getStringRef().str();
  return "/* unresolved: " + op_name + " */";
}

} // namespace hirct
